19. 다음은 JAVA 관한 문제이다. 알맞는 출력값을 작성하시오.
public class ovr1 {
 public static void main(String[] args){
 ovr1 a1 = new ovr1();
 ovr2 a2 = new ovr2();
 System.out.println(a1.sun(3,2) + a2.sun(3,2));
 }

 int sun(int x, int y){
 return x + y;
 }
}

class ovr2 extends ovr1 {

 int sun(int x, int y){
 return x - y + super.sun(x,y);
 }

}
